"use client"; // This must be a client component to use the "sensor" (Observer)

import Share from "@/public/icons/Share";
import { useState, useEffect } from "react";
import { useInView } from "react-intersection-observer";
import { Tweet } from "react-tweet";

export default function LazyTweet({ id }: { id: string }) {
  // 1. The Sensor: Detects when the element is 200px away from the viewport
  const { ref, inView } = useInView({
    triggerOnce: true, // Only trigger once, don't unload if they scroll back up
    rootMargin: "200px 0px", // Start loading 200px before it comes into view
  });

  return (
    <div
      ref={ref}
      style={{ minHeight: "300px", display: "flex", justifyContent: "center" }}
    >
      <div className="flex justify-between ">
        <div className="flex gap-2">
          <Document />
          <span className="text-md font-medium">Youtube </span>
        </div>
        <div className="flex gap-4 text-text-sec">
          <Share />
          <Delete />
        </div>
      </div>
      {inView ? <Tweet id={id} /> : <TweetSkeleton />}
    </div>
  );
}

// A simple placeholder to show while loading (The "Empty Coat Hanger")
function TweetSkeleton() {
  return (
    <div className="border border-gray-200 rounded-xl p-4 w-[500px] h-[300px] animate-pulse bg-gray-50">
      <div className="flex space-x-4">
        <div className="rounded-full bg-gray-200 h-12 w-12"></div>
        <div className="flex-1 space-y-4 py-1">
          <div className="h-4 bg-gray-200 rounded w-3/4"></div>
          <div className="space-y-2">
            <div className="h-4 bg-gray-200 rounded"></div>
            <div className="h-4 bg-gray-200 rounded w-5/6"></div>
          </div>
        </div>
      </div>
    </div>
  );
}
